import{initializeAuth,getCurrentUser,signOut}from './portal-auth.js';import{Logger}from '../shared/logger.js';const TAG='[PortalGuard]';initializeAuth();export function requireAuth(redirectUrl='/auth/login.html'){const user=getCurrentUser();if(!user){Logger.warn(TAG,'User not authenticated,redirecting...');window.location.href=redirectUrl;return false;}return true;}export function checkPermission(permission){const user=getCurrentUser();if(!user)return false;const userPermissions=user.permissions||[];return userPermissions.includes(permission)||user.role==='admin';}export function requirePermission(permission,redirectUrl='/portal/unauthorized.html'){if(!checkPermission(permission)){Logger.warn(TAG,`User lacks permission: ${permission}`);window.location.href=redirectUrl;return false;}return true;}export function isAuthenticated(){return!!getCurrentUser();}export function getUser(){return getCurrentUser();}export async function logout(redirectUrl='/auth/login.html'){await signOut();Logger.info(TAG,'User logged out');window.location.href=redirectUrl;}document.addEventListener('DOMContentLoaded',()=>{Logger.info(TAG,'Portal Guard initialized');});